    public SamlAssertionResult(String subject, java.util.Map<String, List<String>> attributes, String assertionId, String responseId, Instant receivedAt) {
        this.subject = subject;
        this.attributes = attributes;
        this.assertionId = assertionId;
        this.responseId = responseId;
        this.receivedAt = receivedAt;
    }

    public String getSubject() { return subject; }
    public java.util.Map<String, List<String>> getAttributes() { return attributes; }
