class XmlUtil {
    public static String toXml(XMLObject xmlObject) {
        try {
            var marshaller = XMLObjectProviderRegistrySupport.getMarshallerFactory().getMarshaller(xmlObject);
            if (marshaller == null) {
                throw new IllegalStateException("No marshaller for " + xmlObject.getElementQName());
            }
            Element element = marshaller.marshall(xmlObject);
            ByteArrayOutputStream out = new ByteArrayOutputStream();
            javax.xml.transform.Transformer transformer = javax.xml.transform.TransformerFactory.newInstance().newTransformer();
            transformer.setOutputProperty(OutputKeys.OMIT_XML_DECLARATION, "yes");
            transformer.transform(new DOMSource(element), new StreamResult(out));
            return out.toString(StandardCharsets.UTF_8);
        } catch (MarshallingException | javax.xml.transform.TransformerException e) {
            throw new IllegalStateException("Failed to marshal XML", e);
        }
    }

    public static <T extends XMLObject> T fromXml(String xml, Class<T> type) {
        throw new UnsupportedOperationException("XML parsing to SAML objects is application-specific in this template");
    }
}

class SAMLProtocolUtil {
    public static String deflateAndBase64Encode(String xml) {
        try {
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            java.util.zip.Deflater deflater = new java.util.zip.Deflater(java.util.zip.Deflater.DEFLATED, true);
            java.util.zip.DeflaterOutputStream dos = new java.util.zip.DeflaterOutputStream(baos, deflater);
            dos.write(xml.getBytes(StandardCharsets.UTF_8));
            dos.finish();
            dos.close();
            return Base64.getEncoder().encodeToString(baos.toByteArray());
        } catch (Exception e) {
            throw new IllegalStateException("Unable to deflate SAML request", e);
        }
    }
}

